export const wsActivities: Activity[] = [
  {"id":"ws-sink-or-float-tubs","title":"Sink-or-Float Discovery Tubs","altNames":["Will It Float Lab","Float Test Station","Sink or Swim Tubs"],"type":"Water","place":"Both","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Campers predict, then test, whether a tableful of everyday objects sinks or floats in a tub of water.","materials":["Large tubs or buckets, 1 per small group, filled with water","An assortment of small safe objects (cup, sponge, cork, coin, craft stick, rock, crayon, foam sheet scrap)","Paper and markers to make a 'sink / float' chart","Paper towels for drips","Water source to refill"],"materialTags":["Water source","Paper","Markers","Sponges","Craft sticks"],"steps":["Fill a tub with water for each small group and lay out a tray of mixed objects beside it.","Have each group draw a two-column chart on paper labeled 'I think it sinks' and 'I think it floats'.","Before any testing, campers sort every object onto the chart as a prediction.","One at a time, gently lower each object into the water and watch what it actually does.","Move objects that surprised the group to a third 'I was wrong!' pile and talk about why.","After testing, challenge the group to find one floating object they can make sink by changing it (folding the foam, filling the cup).","Fish everything out, dry the tray, and let the next rotation predict fresh."],"notes":"Groups of 3-4 around one tub keeps every hand busy; bigger clusters lead to bystanders. The 'why was I wrong' conversation is the real learning, so don't rush past the surprises. If kids stall, toss in a 'mystery object' and have them debate before it touches the water.","safety":"Keep the tub on the ground or a low sturdy table so nobody leans across a high edge and tips it, and have campers dry their hands before handling the prediction markers so the floor stays dry and non-slip.","ages":["g13","g46"],"rating":0,"media":[{"title":"Sink or Float? Science Experiment for Kids","url":"https://www.youtube.com/watch?v=IHdKD72i_OE"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/water-games/"}],"variations":["Add a 'change its mind' round: campers must turn one floater into a sinker (and vice versa) using only their hands.","Theme it as a shipwreck rescue where floating objects are 'survivors' to be saved and sinkers are 'lost cargo' to chart.","For grades 4-6, have them weigh each object by hand first and predict whether heavy always means sink (it doesn't), then prove it with the floating rock-shaped foam."],"subsets":[["Use buckets if tubs aren't available; one per 3-4 campers","Choose objects that genuinely split the vote, not all obvious"],["Label columns clearly so younger campers can sort by picture if needed"],[],[],["Push for a real reason, not just 'I dunno'"],[],[]]},
  {"id":"ws-pour-and-funnel-station","title":"Pour & Funnel Water Stations","altNames":["Funnel and Tube Play","Water Pouring Lab","Cup and Channel Station"],"type":"Water","place":"Outside","ageMin":6,"ageMax":11,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Cups, paper funnels, and straws become a hands-on water-flow playground for pouring, channeling, and catching.","materials":["Plastic cups of several sizes","Paper rolled into funnels (or paper cups with the bottom torn out)","Straws to use as channels and spouts","Buckets of water to scoop from","Tubs or a second bucket to catch the flow","Paper towels","Water source to refill"],"materialTags":["Paper cups","Straws","Water source","Paper","Paper towels"],"steps":["Set up a station with a full scoop-bucket, an empty catch-tub, and a pile of cups, paper funnels, and straws.","Show campers how to roll a sheet of paper into a funnel and steady it over a cup.","Let them experiment: pour water through the funnel, line straws up as little channels, and watch where the stream goes.","Challenge each camper to move water from the scoop-bucket to the catch-tub WITHOUT pouring directly between them.","Have them tilt and link cups so water cascades from one into the next like a staircase.","Add a 'how few spills' goal and let campers redesign their setup to waste less water.","Reset the station by dumping the catch-tub back and re-stacking the cups."],"notes":"This is open-ended tinkering, so resist over-directing; the discovery is the point. Best in pairs sharing one setup so they problem-solve together. Have a stack of spare paper ready because the first funnels always leak and that's a teachable moment.","safety":"Run this over grass or a designated wet zone since the ground gets soaked, and remind campers that straws are for channeling water only, never for blowing water at a face.","ages":["g13","g46"],"rating":0,"media":[{"title":"How to Set Up a Water Pouring Station","url":"https://www.youtube.com/watch?v=syn3s0m_FBg"}],"links":[{"label":"How-to & more ideas","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Add a height element: prop one cup on a step or block so water falls farther and splashes more.","Turn it into a relay where pairs move a set amount of water cup-to-funnel-to-cup down a line against the clock.","For grades 4-6, give them only three cups and one straw and challenge them to engineer the longest water 'staircase' that still reaches the tub."],"subsets":[[],["Pre-roll one funnel as a model so kids see the cone shape"],[],["Frame the no-direct-pour rule as the puzzle, not a punishment"],[],[],[]]},
  {"id":"ws-rainbow-water-glasses","title":"Make-a-Rainbow Water Glasses","altNames":["Rainbow in a Cup","Color Order Water Line","Liquid Rainbow Row"],"type":"Water","place":"Both","ageMin":7,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Campers mix drops of washable color into a row of water cups to build a glowing seven-cup rainbow.","materials":["Clear plastic cups, 6-7 per group","Washable markers or a few drops of washable paint to tint water","Buckets of clean water to fill cups","Paper towels","Craft sticks for stirring","Water source to refill"],"materialTags":["Paper cups","Markers","Water source","Paper towels","Craft sticks"],"steps":["Line up six or seven clear cups in a row for each group and half-fill each with clean water.","Have campers tint the end cups with the primary colors: red, yellow, and blue, stirring with a craft stick.","Talk through the rainbow order (red, orange, yellow, green, blue) and which two cups they must mix to make the missing colors.","Mix a little red and yellow water into the empty 'orange' cup, yellow and blue into 'green', and so on.","Slide the cups into rainbow order and hold them up to the light to compare shades.","Challenge groups to fine-tune a too-dark or too-pale cup by adding a splash of clear water or another drop of color.","Pour out, rinse the cups, and let the next group build their own rainbow."],"notes":"Washable marker tips swished in water tint it fast and cheap; have spares because kids love saturating the water. Groups of 3-4 sharing one rainbow keeps everyone mixing. The 'which two colors make this one' question is what turns play into a real color-theory lesson.","safety":"Use only washable, non-toxic coloring and clear plastic (never glass) cups, and keep the colored water for looking and mixing, not drinking, with a clearly separate cup of drinking water nearby.","ages":["g13","g46"],"rating":0,"media":[{"title":"Science Activity for Kids: Rainbow in a Cup","url":"https://www.youtube.com/watch?v=iGsZTcGHA1M"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/water-games/"}],"variations":["Make a single giant class rainbow in larger tubs and let each small group own one color.","Add a 'mystery shade' challenge where a counselor mixes a secret color and campers race to match it from scratch.","For grades 4-6, hand them only red, yellow, and blue and have them derive all seven cups themselves, recording the ratios on paper."],"subsets":[["Use truly clear cups so the color shows; cloudy cups hide the effect"],["Swish a marker tip in the water until the color is strong"],["Point to a rainbow poster or the sky if one is visible"],[],[],[],[]]},
  {"id":"ws-foil-boat-regatta","title":"Foil & Cup Boat Regatta","altNames":["Float-Your-Boat Race","Tinfoil Boat Challenge","Cargo Boat Float Test"],"type":"Water","place":"Outside","ageMin":8,"ageMax":14,"durationMin":45,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Campers shape boats from foil, cups, and craft sticks, then race to see whose floats farthest and carries the most cargo.","materials":["Aluminum foil, a sheet per camper","Paper cups and craft sticks for hulls and masts","Masking tape","A long tub, gutter, or a row of buckets as the 'racecourse'","Small weights for cargo (coins, pony beads, or pebbles)","Straws to blow the boats along","Water source"],"materialTags":["Paper cups","Craft sticks","Masking tape","Straws","Water source","Pony beads"],"steps":["Give each camper a sheet of foil and access to cups, craft sticks, and tape to build a boat hull.","Let them design freely, then float-test their boat in a tub and patch any leaks or tips with tape.","Run a 'cargo round': add pony beads or pebbles one at a time and count how many the boat holds before it sinks.","Set up a straight water 'lane' and race boats by blowing through a straw, no touching the boat with hands.","Time or measure each boat's run and tally cargo capacity for a combined champion.","Let campers rebuild and re-race after seeing what made the winning hulls stable.","Dry and collect the foil for recycling and dump the lanes."],"notes":"The redesign-and-retry loop is the gold here, so build in time for a second build. Wide, flat hulls beat deep narrow ones, but let kids discover that. Pair a strong builder with a hesitant one so nobody is stuck with a sinking blob.","safety":"Straws are for blowing the boats only; coach campers to blow across the water surface and never to inhale through a straw near the water, and keep faces back from the lane to avoid splashes to the eyes.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Penny Foil Boat Challenge: Buoyancy STEM Activity","url":"https://www.youtube.com/watch?v=FdXEKUdc8oM"}],"links":[{"label":"How-to & more ideas","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Cargo-only mode: skip the race and crown whoever's boat holds the most weight before sinking.","Add a wind challenge where a craft-stick-and-paper sail must catch a counselor's gentle fan instead of straw-blowing.","For grades 4-6, give a fixed foil size and a strict 60-second build clock, then run elimination heats two boats at a time."],"subsets":[["Provide a model fold (a simple foil tray) for campers who freeze on a blank sheet"],["Keep tape handy; leaks are the most common failure"],["Add cargo slowly so the sink point is dramatic"],["Mark a start and finish on the lane so runs are comparable"],[],[],[]]},
  {"id":"ws-color-mixing-eyedropper-lab","title":"Color-Mixing Drop Lab","altNames":["Eyedropper Color Lab","Drop-by-Drop Mixing","Liquid Color Mixing Trays"],"type":"Water","place":"Both","ageMin":7,"ageMax":13,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Using straws as droppers, campers mix tinted water drop by drop to discover exactly how colors are born.","materials":["Paper plates or muffin-style trays as mixing wells, or rows of cup lids","Cups of red, yellow, and blue tinted water (washable)","Straws to use as droppers (cap the top with a finger to lift water)","White paper to drop colors onto and compare","Paper towels","Water source"],"materialTags":["Paper plates","Paper cups","Straws","Paper","Water source","Paper towels"],"steps":["Set out cups of red, yellow, and blue water and give each camper a straw and a white paper plate as a palette.","Show the dropper trick: dip the straw, cap the top with a fingertip, lift, and release a drop by lifting the finger.","Have campers place a few drops of two primary colors side by side, then watch them swirl into a new color.","Record on white paper which two colors made which result: red plus yellow, blue plus yellow, red plus blue.","Challenge them to make the palest and the darkest version of one color by changing the number of drops.","Try a three-color mix in one well and predict the muddy result before testing.","Rinse straws, refill the color cups, and reset the palettes for the next group."],"notes":"The straw-dropper move feels like magic and gives even fidgety kids fine-motor focus. Keep color cups topped up; pale water mixes weakly. For older grades, the drop-counting turns this into a genuine ratio experiment they can chart.","safety":"Demonstrate the straw is a dropper, not a sipping straw, and keep a clearly marked drinking-water cup elsewhere so nobody mistakes the tinted lab water for a drink.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Color Changing Water Experiment (primary & secondary)","url":"https://www.youtube.com/watch?v=P2F11q9YRCo"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/water-games/"}],"variations":["Drop the colors onto a wet coffee-filter or paper towel instead of a plate to watch them bloom and blend.","Run a 'match my swatch' challenge where campers recreate a color the counselor shows, by drop count alone.","For grades 4-6, require them to log the exact drop ratio that made each secondary color and compare results across the group."],"subsets":[["Cup lids or a paper plate with shallow pools both work as wells"],["Practice the finger-cap lift a couple times over a cup first"],[],["Use a fresh spot on the paper for each combo so results stay clear"],[],[],[]]},
  {"id":"ws-sprinkler-obstacle-course","title":"Sprinkler Splash Obstacle Course","altNames":["Sprinkler Run Course","Wet Obstacle Dash","Splash Zone Course"],"type":"Water","place":"Outside","ageMin":7,"ageMax":14,"durationMin":30,"groupMin":6,"groupMax":24,"energy":3,"prep":"Medium","blurb":"Campers weave, crawl, and leap through a sprinkler-soaked obstacle course timed for the fastest soggy run.","materials":["A sprinkler or hose set to a steady spray","Cones to mark the course path and turns","Hula hoops to crawl or jump through","Boundary markers or chalk for stations","A whistle and a timer","Water source"],"materialTags":["Water source","Cones","Hula hoops","Whistle","Sidewalk chalk"],"steps":["Set up the sprinkler in the middle of an open grassy area so it sprays across the course path.","Lay out a course with cones to weave, a hula hoop to jump through, and a 'crawl zone' chalked under the spray.","Walk the whole group through the course once dry so everyone knows the path and the stations.","Turn on the sprinkler and send campers one at a time, timing each soggy run with the whistle to start.","Each camper must hit every station, including passing fully through the sprinkler spray at least once.","Post times on a chalk board and let campers run a second lap to beat their own first time.","Reset cones that get knocked over between runners and keep the queue back from the wet lane."],"notes":"Send runners on a real gap so nobody bunches up in the spray. Times motivate older kids; for younger ones drop the clock and just let them run it on a loop. The dry walk-through prevents the slips that happen when excited kids meet a wet course cold.","safety":"Wet grass plus speed is the main hazard, so keep the whole course on flat lawn (never pavement), require feet-first slides only if any sliding is allowed, and station a counselor at the slickest turn to slow runners down.","ages":["g13","g46","g79"],"rating":0,"links":[{"label":"How-to & more ideas","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Run it as a team relay where each member tags the next at the finish and total team time wins.","Add 'carry a sponge full of water through without losing it' as a final station to combine speed and care.","For grades 4-6, add a memory twist: change one station's rule each lap so they must listen for the new instruction before launching."],"subsets":[["Aim the sprinkler so the spray crosses the path, not the queue"],["Keep stations simple: weave, hoop, crawl, sprint"],["The dry walk-through is what prevents first-lap wipeouts"],[],[],[],[]]},
  {"id":"ws-water-blob-pavement-art","title":"Water-Blob Pavement Painting","altNames":["Water Painting on Pavement","Evaporation Art","Paint-with-Water Splash Art"],"type":"Water","place":"Outside","ageMin":6,"ageMax":12,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Armed with brushes and cups of plain water, campers paint giant pictures on warm pavement and race the sun as they vanish.","materials":["Paintbrushes of varied sizes, 1 per camper","Sponges cut into shapes for stamping","Paper cups or small buckets of plain water","A sunny stretch of pavement or a wall","Paper towels","Water source to refill"],"materialTags":["Paintbrushes","Sponges","Paper cups","Water source","Paper towels"],"steps":["Give each camper a brush and a cup of plain water and claim a square of warm, dry pavement.","Show how the water 'paint' shows up dark on the dry pavement and slowly fades as it evaporates.","Let campers paint shapes, names, and pictures, racing to finish before their lines disappear.","Hand out sponge stamps so they can press shapes and splotchy textures alongside brushwork.","Call a 'fastest fade' challenge: paint a shape and time how long it stays visible in the sun versus the shade.","Have campers paint one collaborative giant mural across several squares before it all evaporates.","Refill water cups as needed; there is nothing to clean up but the empty cups."],"notes":"Zero mess and endlessly repeatable, perfect for a hot pavement day. The evaporation race is a sneaky science lesson about sun, heat, and shade. Pair the sun-versus-shade timing observation with a quick 'why?' and you've got real inquiry, not just play.","safety":"Pavement in full sun gets hot enough to feel through shoes, so keep campers shod, paint standing or kneeling on a towel rather than sitting bare-legged on the hot surface, and watch that wet patches stay thin so the ground doesn't get slick.","ages":["g13","g46"],"rating":0,"media":[{"title":"STEM: Evaporation Art (paint with water)","url":"https://www.youtube.com/watch?v=zGzv7SBx9Iw"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/water-games/"}],"variations":["Tint the water faintly with a drop of washable color so the strokes show even bolder before they fade.","Race in pairs: one paints in the sun, one in the shade, and they compare how much longer the shaded art lasts.","For grades 4-6, turn it into a relay mural where each runner adds one element to a growing picture before it evaporates."],"subsets":[["Pick pavement that's dry and sun-warmed so the contrast pops"],["Point out the dark-then-fading effect as the hook"],[],["Cut simple sponge shapes ahead: circle, star, leaf"],["Use the shade-vs-sun timing to spark the 'why' question"],[],[]]},
  {"id":"ws-spinning-water-wheel-cups","title":"Spinning Water-Wheel Cups","altNames":["Paper Cup Water Wheel","Waterwheel Spin Lab","Pour-Powered Wheel"],"type":"Water","place":"Outside","ageMin":8,"ageMax":14,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Campers build a little paper-cup water wheel and discover how a poured stream spins it into motion.","materials":["Paper cups, several per builder, with one as the wheel hub","Craft sticks or straws for paddles and an axle","Masking tape","A pencil or straw to act as the axle to hold the wheel","Buckets and cups of water to pour","Paper towels","Water source"],"materialTags":["Paper cups","Craft sticks","Straws","Masking tape","Water source","Paper towels"],"steps":["Have each builder tape several small paddle pieces (cut cup walls or craft sticks) evenly around one cup to make a wheel.","Push a straw or pencil straight through the center of the cup as the axle so the wheel can spin freely.","Hold the axle level by resting its ends on two stacked-cup towers or two helpers' hands.","Slowly pour a steady stream of water onto the top paddles and watch the wheel turn.","Experiment: pour faster, aim higher on the paddles, or add more paddles and note what spins it best.","Have builders predict and then test which change makes the wheel spin fastest.","Dump the catch bucket, dry the wheels, and let the next group build and test."],"notes":"The build takes patience, so this suits older campers or pairs where one tapes while one holds. Evenly spaced paddles are the secret to a smooth spin; lopsided ones wobble and stall, which is itself a great lesson. Keep a catch bucket under the wheel so the poured water recycles.","safety":"Keep the pour gentle and aimed at the wheel, not at hands or faces, and steady the axle on a stable rest so a spinning wheel can't flick water into a watcher's eyes; have pourers stand to the side, not directly over a tipping cup.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"How to Make a Water Wheel Science Project","url":"https://www.youtube.com/watch?v=hKalwhnCIfE"}],"links":[{"label":"How-to & more ideas","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Race two wheels side by side, each fed by the same size pour, to see whose paddle design spins faster.","Tie a short yarn to the axle with a paper-cup 'bucket' to lift, turning the wheel into a tiny machine that raises a load.","For grades 4-6, hold the pour constant and let them vary only paddle count or size, charting the result like a real experiment."],"subsets":[["Cut paddles to the same size so the wheel stays balanced"],["A straw axle spins easier than a thick pencil for light wheels"],["Two cup-towers make a steady, hands-free axle rest"],["Aim the stream at the top paddles for the most push"],[],[],[]]},
  {"id":"ws-water-cycle-race","title":"Water Cycle Relay Lab","altNames":["Evaporation Race","Splash to Vapor Challenge","Puddle Cycle Game"],"type":"Water","place":"Outside","ageMin":8,"ageMax":13,"durationMin":30,"groupMin":6,"groupMax":24,"energy":2,"prep":"Low","blurb":"Teams act out evaporation, clouds, and rain in a relay that turns the water cycle into a soggy race.","materials":["Plastic cups, 1 per team","Buckets of water as the 'ocean' at the start","Sponges as 'clouds' to soak and carry","Paper plates or cups as the 'cloud' collection point","Cones to mark the cycle stations","Chalk to label Ocean, Sky, and Rain stations","Water source"],"materialTags":["Paper cups","Sponges","Water source","Cones","Sidewalk chalk","Paper plates"],"steps":["Chalk three stations in a loop and label them Ocean, Sky (cloud), and Rain, with cones marking the path between.","Explain the cycle: water evaporates from the ocean, gathers in a cloud, then falls as rain back to the ground.","At Ocean, the first runner soaks a sponge ('evaporates' water) and carries it to the Sky station.","At Sky, they squeeze the sponge into the team's 'cloud' cup, then run to the Rain station and pour a splash onto the ground.","The runner races the empty cup back to Ocean and tags the next teammate to repeat the cycle.","Play for a set time; the team that completed the most full cycles (or filled their cloud cup highest) wins.","Reset cups and refill the ocean buckets between rounds."],"notes":"Naming each leg as a real cycle stage makes the science stick without slowing the game down. Even teams of 4-6 keep the loop busy. If the science framing loses younger kids, just run it as a sponge-carry relay and add the vocabulary on round two.","safety":"The Sky and Rain stations get wet and slick, so place them on flat grass, keep the run between stations on dry footing where possible, and coach runners to slow at the squeeze-and-pour points rather than skid into them.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Wonderful Water Cycle Activities for Kids","url":"https://www.youtube.com/watch?v=6uahLx6600g"}],"links":[{"label":"How-to & more ideas","url":"https://ultimatecampresource.com/camp-games/water-games/"}],"variations":["Add a 'condensation' station where the cloud cup must reach a fill line before that team is allowed to 'rain'.","Run it cooperatively: the whole group races one big cycle against a timer instead of team-versus-team.","For grades 4-6, have each team explain which station they're at as they tag off, reinforcing the vocabulary under pressure."],"subsets":[["Keep the loop tight so the cycle is quick and repeatable"],["Tell the cycle as a story before the first whistle"],[],["A clear fill line on the cloud cup makes 'most water' easy to judge"],[],[],[]]},
  {"id":"ws-leak-race-flow-lab","title":"Leaky Cup Flow Race","altNames":["Hole Punch Water Race","Drain Speed Lab","Leaky Cup Challenge"],"type":"Water","place":"Both","ageMin":8,"ageMax":13,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Campers punch holes in cups and race to predict which design drains its water the fastest.","materials":["Paper or plastic cups, several per group","A pencil or pushpin (counselor-held) to punch holes","Buckets of water and a catch-tub","Paper and markers to record predictions","A timer or stopwatch","Paper towels","Water source"],"materialTags":["Paper cups","Water source","Paper","Markers","Paper towels"],"steps":["Have each group take several cups and ask a counselor to punch a different hole pattern in each (one hole, three holes, one big hole, holes high vs low).","Before testing, campers predict on paper which cup will empty fastest and which slowest.","Fill the first cup over the catch-tub, lift it, and time how long it takes to drain completely.","Record each cup's drain time and compare against the predictions.","Discuss what mattered: number of holes, hole size, or where the holes sat on the cup.","Challenge the group to design a cup that drains in exactly five seconds and test it.","Empty the catch-tub back into the supply and reset for the next group."],"notes":"Counselors handle all hole-punching so the tool stays controlled. The 'design for exactly five seconds' challenge is what separates tinkering from real engineering thinking. Have plenty of spare cups; kids will want to keep iterating.","safety":"Only counselors handle the pushpin or sharp tool used to punch holes, kept well away from campers, and the draining is done over a tub so the floor stays dry and footing stays sure.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Water Bottle With Holes Experiment","url":"https://www.youtube.com/watch?v=kVCoNHySyuk"}],"links":[{"label":"How-to & more ideas","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"}],"variations":["Race two leaky cups head to head and let campers bet which empties first before the start.","Turn it into a timer challenge: punch a cup so it drains in the exact span of a sung verse.","For grades 4-6, hold hole size constant and vary only hole position, so they isolate height-of-hole as the single variable."],"subsets":[["Make the hole patterns genuinely different so results vary","Counselor does all punching with the sharp tool"],["Push campers to commit to an order, not hedge"],["Start and stop the timer on a clear signal so times are fair"],[],[],[],[]]},
];
